$(document).ready(function(){$('#modalDueDateInput').datepicker({dateFormat:'yy-mm-dd',minDate:0});$(document).on('click','#modalSetDueDateTrigger',function(e){e.preventDefault();$('#dueDatePickerContainer').show();$('#modalDueDateInput').val(originalTaskData.due_date||'').focus()});$(document).on('click','#modalCancelDueDateBtn',function(){$('#dueDatePickerContainer').hide();$('#modalDueDateInput').val('')});$(document).on('click','#modalSaveDueDateBtn',function(){const taskId=$('#modalTaskId').val();const newDueDate=$('#modalDueDateInput').val().trim();const $btn=$(this);if(!newDueDate){return alert('Vui lòng chọn ngày hết hạn.')}
const url=window.routeUrls.tasksUpdateBase.replace(':taskIdPlaceholder',taskId);const title=$('#modalTaskTitleInput').val()||(window.originalTaskData?originalTaskData.title:'');$btn.prop('disabled',!0);$.ajax({url:url,method:'PUT',data:{title:title,due_date:newDueDate,_token:$('meta[name="csrf-token"]').attr('content')},success:function(response){if(response.success){$('#dueDatePickerContainer').hide();location.reload()}else{alert(response.message||'Không thể cập nhật ngày hết hạn.')}},error:function(xhr){const msg=xhr.responseJSON&&xhr.responseJSON.message?xhr.responseJSON.message:'Không thể cập nhật ngày hết hạn.';alert(msg)},complete:function(){$btn.prop('disabled',!1)}})})})